    int findUnsortedSubarray(vector<int>& nums) {
        int n = nums.size();
        int max_so_far = 0, max_ending_here = 0;

        for (int i = 0; i < n; i++) {
            max_ending_here = max(nums[i], max_ending_here + nums[i]);
            if (max_so_far < max_ending_here) {
                max_so_far = max_ending_here;
            }
        }

        return max_so_far;
    }
};
